import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { connectWallet } from '../utils/walletConnector';

const Login = () => {
  const [address, setAddress] = useState('');
  const [network, setNetwork] = useState('1'); // По умолчанию Ethereum
  const [walletType, setWalletType] = useState('Trust Wallet'); // По умолчанию Trust Wallet
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState('');
  const [isMobileDevice, setIsMobileDevice] = useState(false);

  const { login } = useAuth();
  const navigate = useNavigate();

  // Определяем, является ли устройство мобильным
  useEffect(() => {
    const checkMobile = () => {
      return /Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(navigator.userAgent);
    };
    setIsMobileDevice(checkMobile());
  }, []);

  // Определяем доступные кошельки в зависимости от выбранной сети
  const getAvailableWallets = () => {
    if (network === '1') { // Ethereum
      return ['Trust Wallet'];
    } else if (network === '2') { // TON
      return ['Trust Wallet', 'Tonkeeper'];
    }
    return ['Trust Wallet'];
  };

  // Обработчик изменения сети
  const handleNetworkChange = (e) => {
    const newNetwork = e.target.value;
    setNetwork(newNetwork);

    // Если выбран Ethereum и текущий кошелек - Tonkeeper, меняем на Trust Wallet
    if (newNetwork === '1' && walletType === 'Tonkeeper') {
      setWalletType('Trust Wallet');
    }
  };

  // Обработчик нажатия на кнопку подключения кошелька
  const handleWalletConnect = async (e) => {
    e.preventDefault();

    try {
      setLoading(true);
      setError('');
      setSuccess('');

      // Определение сети (ETH или TON)
      const networkType = network === '1' ? 'ETH' : 'TON';

      // Log some debugging information
      console.log('Attempting to connect to wallet:', {
        networkType,
        walletType,
        isMobileDevice,
        userAgent: navigator.userAgent
      });

      try {
        // Подключение к кошельку и получение адреса и подписи
        const { address, signature } = await connectWallet(networkType, walletType);

        // Установка адреса в форму
        setAddress(address);

        // Если получен адрес и подпись, выполняем вход
        if (address && signature) {
          await login(address, network, signature, walletType);

          setSuccess(`Вход через ${walletType} выполнен успешно!`);

          // Перенаправляем пользователя на страницу профиля
          setTimeout(() => {
            navigate('/profile');
          }, 1500);
        }
      } catch (connectionError) {
        console.error('Connection Error Details:', connectionError);

        // Check for browser extension detection issues
        if (connectionError.message && connectionError.message.includes('extension not detected')) {
          setError(`Расширение ${walletType} не обнаружено. Убедитесь, что оно установлено и активировано.`);
          return;
        }

        // Проверяем, содержит ли ошибка сообщение об открытии приложения
        if (connectionError.message && connectionError.message.includes('Opening')) {
          setSuccess(connectionError.message);
          // На мобильных устройствах сообщение об успешном открытии приложения
          if (isMobileDevice) {
            setSuccess(`Открывается ${walletType}. Пожалуйста, завершите процесс подключения в приложении.`);
          }
        } else {
          throw connectionError;
        }
      }
    } catch (error) {
      console.error('Ошибка при подключении кошелька:', error);

      // More detailed error messages based on common issues
      if (error.code === -32002) {
        setError('Запрос на подключение уже в процессе. Проверьте всплывающие окна вашего кошелька.');
      } else if (error.code === 4001) {
        setError('Запрос на подключение был отклонен пользователем.');
      } else if (error.message && error.message.includes('user rejected')) {
        setError('Вы отклонили запрос на подключение к кошельку.');
      } else {
        setError(error.message || 'Ошибка при подключении кошелька');
      }
    } finally {
      setLoading(false);
    }
  };

  // Возвращает текст кнопки в зависимости от типа устройства
  const getButtonText = () => {
    if (loading) return 'Подключение...';
    if (isMobileDevice) return `Открыть ${walletType}`;
    return `Подключить ${walletType}`;
  };

  return (
    <div className="container">
      <div className="card" style={{ maxWidth: '500px', margin: '40px auto' }}>
        <h2>Вход через криптокошелек</h2>

        {error && <div className="alert alert-danger">{error}</div>}
        {success && <div className="alert alert-success">{success}</div>}

        <form onSubmit={handleWalletConnect}>
          <div className="form-group">
            <label htmlFor="network" className="form-label">
              Сеть
            </label>
            <select
              id="network"
              className="form-control"
              value={network}
              onChange={handleNetworkChange}
              disabled={loading}
            >
              <option value="1">Ethereum</option>
              <option value="2">TON</option>
            </select>
          </div>

          <div className="form-group">
            <label htmlFor="walletType" className="form-label">
              Тип кошелька
            </label>
            <select
              id="walletType"
              className="form-control"
              value={walletType}
              onChange={(e) => setWalletType(e.target.value)}
              disabled={loading}
            >
              {getAvailableWallets().map(wallet => (
                <option key={wallet} value={wallet}>
                  {wallet}
                </option>
              ))}
            </select>
          </div>

          <button
            type="submit"
            className="btn"
            style={{ width: '100%' }}
            disabled={loading}
          >
            {getButtonText()}
          </button>
        </form>

        <div style={{ marginTop: '20px', textAlign: 'center', fontSize: '0.9rem' }}>
          <p>
            {isMobileDevice ? (
              <>
                Нажмите кнопку, чтобы открыть приложение кошелька
                <br />
                {network === '1' ? 'Для Ethereum доступен только Trust Wallet' : 'Для TON доступны Trust Wallet и Tonkeeper'}
              </>
            ) : (
              <>
                Для входа требуется расширение браузера
                <br />
                - Для Ethereum доступен только Trust Wallet.
                <br />
                - Для TON доступны Trust Wallet и Tonkeeper.
              </>
            )}
          </p>
          {!isMobileDevice && (
            <p style={{ marginTop: '10px', fontStyle: 'italic' }}>
              <strong>Примечание:</strong> Если у вас не установлено нужное расширение,
              <br />система предложит его установить.
            </p>
          )}

          {/* Troubleshooting section for users with detection issues */}
